{
  "data": [
    {
      "type": "osm",
      "queryArea": { "geocodeArea": "Rio de Janeiro", "areas": ["Niter\u00f3i"] },
      "outputTableName": "table_osm",
      "autoLoadLayers": { "layers": ["surface", "parks", "water", "roads", "buildings"], "dropOsmTable": true }
    },
    {
      "type": "join",
      "tableRootName": "table_osm_roads",
      "tableJoinName": "table_osm_buildings",
      "near": { "distance": 100 },
      "groupBy": [{ "column": "height", "aggregateFn": "avg" }]
    }
  ],
  "compute": [{
    "dataRef": "table_osm_roads",
    "attributes": { "h": "sjoin.avg.height" },
    "outputColumnName": "building_height_index",
    "wglsFunction": "if (h <= 0.0) { return 0.0; } return h;"
  }],
  "map": {
    "layerRefs": [
      { "dataRef": "table_osm_surface" },
      { "dataRef": "table_osm_parks" },
      { "dataRef": "table_osm_water" },
      { "dataRef": "table_osm_buildings" },
      {
        "dataRef": "table_osm_roads",
        "isPick": true,
        "getFnv": "compute.building_height_index",
        "getFnvType": "quantitative",
        "defaultFnv": 0
      }
    ]
  },
  "plot": {
    "dataRef": "table_osm_roads",
    "mark": "scatter",
    "axis": ["lanes", "sjoin.avg.height"],
    "title": "Road capacity vs nearby building height (Niter\u00f3i)",
    "events": ["brush"],
    "mapRef": "table_osm_roads"
  }
}
